/**
 * IVX Member Service — Client-Side API
 *
 * Communicates with the backend member registration and verification API.
 * Used by member-register, member-verify, and member-dashboard screens.
 */

const API_BASE = process.env.EXPO_PUBLIC_IVX_API_BASE_URL
  ? process.env.EXPO_PUBLIC_IVX_API_BASE_URL.replace(/\/+$/, '')
  : 'https://api.ivxholding.com';

export type MemberRoleInterest =
  | 'buyer'
  | 'investor'
  | 'jv_partner'
  | 'broker'
  | 'agent'
  | 'land_owner'
  | 'jv_deals'
  | 'tokenized';

export interface RegisterPayload {
  email: string;
  password: string;
  firstName: string;
  lastName: string;
  phone: string;
  country: string;
  zipCode: string;
  roles: MemberRoleInterest[];
  acceptTerms: boolean;
  pictureUrl?: string;
}

export interface RegisterResult {
  success: boolean;
  message: string;
  userId?: string;
  email?: string;
  requiresVerification: boolean;
}

export interface VerifyResult {
  success: boolean;
  message: string;
  verified: boolean;
}

export interface MemberProfile {
  id: string;
  email: string;
  firstName: string;
  lastName: string;
  phone: string;
  country: string;
  role: string;
  status: string;
  kycStatus: string;
  emailVerified: boolean;
  phoneVerified: boolean;
  totalInvested: number;
  totalReturns: number;
  createdAt: string;
  updatedAt: string;
}

export interface ProfileResult {
  success: boolean;
  profile?: MemberProfile;
}

export interface VerificationStatusResult {
  success: boolean;
  emailVerified: boolean;
  phoneVerified: boolean;
  bothVerified: boolean;
}

async function apiPost<T>(path: string, body: Record<string, unknown>): Promise<T> {
  const url = `${API_BASE}${path}`;
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  if (!response.ok) {
    const errorBody = await response.json().catch(() => ({}));
    return { success: false, message: (errorBody as any)?.message || `Request failed (${response.status})` } as unknown as T;
  }
  return response.json() as Promise<T>;
}

